# Recursive DFS on tree
def dfs_tree(root):
    if not root:
        return 0
    left = dfs_tree(root.left)
    right = dfs_tree(root.right)
    return 1 + max(left, right)

def maxDepth(root):
    if not root:
        return 0
    return 1 + max(maxDepth(root.left), maxDepth(root.right))

